import{_ as t,o,c as n,ag as a}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"ADR-0005: Hosted Fleet Orchestration with Enrolled Edge Nodes","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/10_governance/50_decisions/adr-0005_fleet_orchestration.md","filePath":"10_core/10_governance/50_decisions/adr-0005_fleet_orchestration.md"}'),r={name:"10_core/10_governance/50_decisions/adr-0005_fleet_orchestration.md"};function i(s,e,l,c,d,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-0005-hosted-fleet-orchestration-with-enrolled-edge-nodes" tabindex="-1">ADR-0005: Hosted Fleet Orchestration with Enrolled Edge Nodes <a class="header-anchor" href="#adr-0005-hosted-fleet-orchestration-with-enrolled-edge-nodes" aria-label="Permalink to &quot;ADR-0005: Hosted Fleet Orchestration with Enrolled Edge Nodes&quot;">​</a></h1><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The documentation previously outlined a &quot;Local Admin Control Plane&quot; consisting of a local fastAPI server running on the developer workstation directing jobs and controlling files. As the system scales to ingest files and run jobs across multiple nodes, keeping the control plane tied to the individual local machine becomes an operational bottleneck and architectural flaw.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ul><li><strong>Hosted Admin</strong> is the singular orchestration authority and fleet control plane.</li><li><strong>Local Nodes</strong> are redefined as agents/runtimes for execution only, not as orchestration centers.</li><li>Devices are conceptually &quot;enrolled&quot;. Devices ingest data strictly from their assigned paths or a drop zone.</li><li>All promoted records must still enter the system through explicitly governed <code>QiArchive</code> processes.</li><li>Local APIs are strictly internal agent execution endpoints, no longer the primary administration control plane.</li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>This establishes a cleaner separation of concerns. The server-side Admin dictates jobs, configurations, and fleet monitoring, whilst multiple generic edge nodes simply report health and ingest content from their given assignments. This formalizes a master/worker &quot;control model flip&quot;, solving discrepancies between the local-control phrasing and the actual fleet needs.</p>',7)])])}const _=t(r,[["render",i]]);export{p as __pageData,_ as default};
